import { Component, signal } from '@angular/core';
import { AXBarChartComponent } from '@acorex/charts/bar-chart';
import { AXBarChartData } from '@acorex/charts/bar-chart';
import { AXBarChartOption } from '@acorex/charts/bar-chart';
import { AXBarChartClickEvent } from '@acorex/charts/bar-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Bar Chart</h2>
      <ax-bar-chart 
        [data]="showcaseData()" 
        [options]="showcaseOptions()"
        (barClick)="onBarClick($event)"
      />
      <div class="chart-info">
        <p>Click on any bar to see detailed information</p>
      </div>
    </div>
  `,
  imports: [AXBarChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
    }
    .chart-info {
      margin-top: 1rem;
      text-align: center;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class BarChartShowcaseComponent {
  showcaseData = signal<AXBarChartData[]>([
    { id: 'sales', label: 'Sales', value: 45000, color: '#3498db' },
    { id: 'marketing', label: 'Marketing', value: 32000, color: '#e74c3c' },
    { id: 'development', label: 'Development', value: 38000, color: '#2ecc71' },
    { id: 'support', label: 'Support', value: 25000, color: '#f39c12' },
    { id: 'research', label: 'Research', value: 18000, color: '#9b59b6' }
  ]);

  showcaseOptions = signal<AXBarChartOption>({
    showXAxis: true,
    showYAxis: true,
    showGrid: true,
    showTooltip: true,
    showDataLabels: true,
    width: 600,
    height: 400,
    barWidth: 80,
    cornerRadius: 6,
    xAxisLabel: 'Departments',
    yAxisLabel: 'Budget ($)',
    animationDuration: 1500,
    animationEasing: 'cubic-out'
  });

  onBarClick(event: AXBarChartClickEvent): void {
    console.log('Bar clicked:', event.item);
    // Handle bar click interaction
  }
}
